  98→        const centeredY = (stageHeight - scaledHeight) / 2;
  99→        minY = centeredY;
 100→        maxY = centeredY;
 101→    }
 102→
 103→    return {
 104→        scale,
 105→        x: clamp(candidate?.x || 0, minX, maxX),
 106→        y: clamp(candidate?.y || 0, minY, maxY)
 107→    };
 108→};
 109→
 110→const getTouchGeometry = (nativeEvent, stage) => {
 111→    const touches = nativeEvent?.touches;
 112→    if(!stage || !touches || touches.length < 2){
 113→        return null;
 114→    }
 115→
 116→    const bounds = stage.container()?.getBoundingClientRect();
 117→    if(!bounds){
 118→        return null;
 119→    }
 120→
 121→    const first = touches[0];
 122→    const second = touches[1];
 123→    const firstPoint = {x: first.clientX - bounds.left, y: first.clientY - bounds.top};
 124→    const secondPoint = {x: second.clientX - bounds.left, y: second.clientY - bounds.top};
 125→
 126→    return {
 127→        center: {x: (firstPoint.x + secondPoint.x) / 2, y: (firstPoint.y + secondPoint.y) / 2},
 128→        distance: Math.hypot(secondPoint.x - firstPoint.x, secondPoint.y - firstPoint.y)
 129→    };
 130→};
 131→
 132→const useLoadedImage = (src) => {
 133→    const [image, setImage] = useState(null);
 134→
 135→    useEffect(() => {
 136→        if(!src){
 137→            setImage(null);
 138→            return;
 139→        }
 140→
 141→        const img = new window.Image();
 142→        img.crossOrigin = "anonymous";
 143→        img.onload = () => setImage(img);
 144→        img.onerror = () => setImage(null);
 145→        img.src = src;
 146→
 147→        return () => {
 148→            img.onload = null;
 149→            img.onerror = null;
 150→        };
 151→    }, [src]);
 152→
 153→    return image;
 154→};
