 611→        } else {
 612→            updateImage(selectedObject.id, (image) => ({scaleX: image.scaleX === -1 ? 1 : -1}));
 613→        }
 614→    };
 615→
 616→    const getPointerInCanvasSpace = (stage) => {
 617→        const pointer = stage?.getPointerPosition();
 618→        if(!pointer){
 619→            return null;
 620→        }
 621→        const activeViewport = viewportRef.current;
 622→        const totalScale = fitScale * activeViewport.scale;
 623→        const totalX = fitOffsetX + activeViewport.x;
 624→        const totalY = fitOffsetY + activeViewport.y;
 625→        return {
 626→            x: clamp((pointer.x - totalX) / totalScale, 0, stageWidth),
 627→            y: clamp((pointer.y - totalY) / totalScale, 0, stageHeight)
 628→        };
 629→    };
 630→
 631→    const getNormalizedPointer = (stage) => {
 632→        const worldPointer = getPointerInCanvasSpace(stage);
 633→        if(!worldPointer){
 634→            return null;
 635→        }
 636→        return {
 637→            x: stageWidth > 0 ? worldPointer.x / stageWidth : 0,
 638→            y: stageHeight > 0 ? worldPointer.y / stageHeight : 0
 639→        };
 640→    };
 641→
 642→    const cancelDrawingSession = () => {
 643→        doodlePointsRef.current = [];
 644→        setCurrentDoodlePoints([]);
 645→        setIsDrawing(false);
 646→    };
 647→
 648→    const maybeBeginPinchGesture = (event) => {
 649→        const nativeEvent = event?.evt;
 650→        const stage = event?.target?.getStage?.();
 651→        const gesture = getTouchGeometry(nativeEvent, stage);
 652→        if(!gesture || gesture.distance < 6){
 653→            return false;
 654→        }
 655→        if(nativeEvent?.cancelable){
 656→            nativeEvent.preventDefault();
 657→        }
 658→        pinchStateRef.current = {
 659→            isActive: true,
 660→            lastDistance: gesture.distance,
 661→            lastCenter: gesture.center
 662→        };
 663→        cancelDrawingSession();
 664→        return true;
 665→    };
 666→
 667→    const maybeHandlePinchMove = (event) => {
 668→        const nativeEvent = event?.evt;
 669→        const stage = event?.target?.getStage?.();
 670→        const gesture = getTouchGeometry(nativeEvent, stage);
 671→        if(!gesture){
 672→            return false;
 673→        }
 674→        if(nativeEvent?.cancelable){
 675→            nativeEvent.preventDefault();
 676→        }
 677→
 678→        const pinchState = pinchStateRef.current;
 679→        if(!pinchState.isActive){
 680→            pinchStateRef.current = {
 681→                isActive: true,
 682→                lastDistance: gesture.distance,
 683→                lastCenter: gesture.center
 684→            };
 685→            return true;
 686→        }
 687→
 688→        const lastDistance = pinchState.lastDistance || gesture.distance;
 689→        const distanceRatio = gesture.distance / Math.max(lastDistance, 1);
 690→        const currentViewport = viewportRef.current;
 691→        const nextScale = clamp(currentViewport.scale * distanceRatio, MIN_VIEWPORT_SCALE, MAX_VIEWPORT_SCALE);
 692→        const anchorCenter = pinchState.lastCenter || gesture.center;
 693→        const currentTotalScale = fitScale * currentViewport.scale;
 694→        const currentTotalX = fitOffsetX + currentViewport.x;
 695→        const currentTotalY = fitOffsetY + currentViewport.y;
 696→        const nextTotalScale = fitScale * nextScale;
 697→        const worldPoint = {
 698→            x: (anchorCenter.x - currentTotalX) / currentTotalScale,
 699→            y: (anchorCenter.y - currentTotalY) / currentTotalScale
 700→        };
 701→        updateViewport({
 702→            scale: nextScale,
 703→            x: gesture.center.x - worldPoint.x * nextTotalScale - fitOffsetX,
 704→            y: gesture.center.y - worldPoint.y * nextTotalScale - fitOffsetY
 705→        });
 706→        pinchStateRef.current = {
 707→            isActive: true,
 708→            lastDistance: gesture.distance,
 709→            lastCenter: gesture.center
 710→        };
 711→        return true;
 712→    };
 713→
 714→    const maybeCompletePinchGesture = (event) => {
 715→        if(!pinchStateRef.current.isActive){
