 74→const sanitizeNormalizedPoints = (rawPoints) => {
 75→    if(!Array.isArray(rawPoints)){
 76→        return [];
 77→    }
 78→
 79→    const numericPoints = rawPoints
 80→        .map((point) => Number(point))
 81→        .filter((point) => !Number.isNaN(point))
 82→        .map((point) => clamp(point, 0, 1));
 83→
 84→    if(numericPoints.length < 2){
 85→        return [];
 86→    }
 87→
 88→    return numericPoints.length % 2 === 0
 89→        ? numericPoints
 90→        : numericPoints.slice(0, -1);
