111→const getSnippetMetrics = (snippet, stageWidth) => {
112→    const sizeScale = Number.isFinite(snippet.sizeScale) ? snippet.sizeScale : 1;
113→    const styleKey = FONT_STYLE_MAP[snippet.fontStyle] || "serif";
114→    const baseFontSize = styleKey === "bold" ? 34 : styleKey === "handwritten" ? 32 : 30;
115→    const fontSize = clamp(baseFontSize * sizeScale, 18, 92);
116→    const estimatedWidth = Math.max(120, Math.min(stageWidth * 0.78, Math.round((snippet.text.length || 1) * fontSize * 0.58)));
117→    const charsPerLine = Math.max(8, Math.floor(estimatedWidth / (fontSize * 0.56)));
118→    const lineCount = Math.max(1, Math.ceil((snippet.text.length || 1) / charsPerLine));
119→    const height = Math.max(68, Math.round(lineCount * fontSize * 1.14 + 18));
120→
121→    return {width: estimatedWidth, height, fontSize};
122→};
